window.addEventListener("load",()=>{const o=new URLSearchParams(window.location.search).get("error");o&&(Swal.fire({title:"Error de Acceso",text:o,icon:"error",confirmButtonColor:"#4f46e5",confirmButtonText:"Entendido",background:document.documentElement.classList.contains("dark")?"#1e293b":"#ffffff",color:document.documentElement.classList.contains("dark")?"#f1f5f9":"#1e293b"}),window.history.replaceState({},document.title,window.location.pathname))});
